/**
 * Pure transcript renderer for the focused-stream overlay.
 *
 * Takes a Run and a set of view options, returns a string[] (one entry per
 * rendered line, each line constrained to `width` columns). No TUI imports,
 * no theme dependency, no I/O — the Component layer is responsible for
 * styling and rendering this output.
 */

import type { AgentMessage } from "@earendil-works/pi-agent-core";
import { truncateToWidth, visibleWidth, wrapTextWithAnsi } from "@earendil-works/pi-tui";
import type { Run } from "./types.ts";
import { elapsedStr, formatUsage } from "./runs.ts";
import { STATUS_GLYPH } from "./status-glyph.ts";
import { summarizeToolArgs } from "./tool-summary.ts";
import { formatToolCallShort } from "./event-handler.ts";

export interface TranscriptOptions {
  /** Hard wrap width; lines that exceed it are wrapped or truncated. */
  width: number;
  /** When true, toolCall parts collapse to a single chevron line. */
  collapseToolCalls: boolean;
  /** When true, thinking parts are shown; otherwise hidden. */
  showThinking: boolean;
  /**
   * Slice 5: optional fold-expansion query. When provided, the
   * renderer asks `isExpanded(key, defaultFalse)` per block and
   * bypasses the fold cap when the answer is true. When omitted,
   * fold caps always apply with the standard limits.
   *
   * Block key shapes:
   *   - tool call with `id`: `tool:<id>`
   *   - tool call without id: `tool:<msgIdx>:<partIdx>`
   *   - thinking part: `thinking:<msgIdx>:<partIdx>`
   */
  isExpanded?: (key: string, defaultExpanded: boolean) => boolean;
}

// Slice 5 fold limits. These are total emitted-line counts for the
// block (renderToolCall expanded / renderThinking output): when the
// block produces strictly more lines than the limit, the renderer
// keeps the first `LIMIT` lines and replaces the tail with a single
// fold marker.
const TOOL_CALL_FOLD_LIMIT = 12;
const THINKING_FOLD_LIMIT = 20;

/**
 * Build the canonical fold-marker line. Two leading spaces, U+22EF
 * ("midline horizontal ellipsis"), positive count, two-space gap
 * before the parenthetical hint.
 *
 * Width-clip handled by the caller via `truncateOrPad`.
 */
function foldMarker(hidden: number): string {
  return `  ⋯ ${hidden} more lines  (e expand all · E collapse all)`;
}

/**
 * Cap a rendered block at `limit` lines. When `block.length > limit`,
 * returns the first `limit` lines with a fold marker appended
 * (`limit + 1` lines total). Otherwise returns the input untouched.
 */
function capBlock(block: string[], limit: number, width: number): string[] {
  if (block.length <= limit) return block;
  const hidden = block.length - limit;
  return [...block.slice(0, limit), truncateOrPad(foldMarker(hidden), width)];
}

// ── Header ────────────────────────────────────────────────────────────

export function renderHeader(run: Run, width: number): string[] {
  const elapsed = elapsedStr(run.startTime, run.finishedAt);
  const usage = formatUsage(run.usage);
  const glyph = STATUS_GLYPH[run.status] ?? "·";

  const baseLeft = `${glyph} ${run.persona} (${run.id}) — ${run.status} ${elapsed}`;
  const right = usage ? `[${usage}]` : "";
  const sep = "─".repeat(Math.max(0, width));

  // Slice 5b: optionally append a derived activity field. Width discipline is
  // load-bearing — if appending the activity (with separator) would push the
  // header past the requested width, we shrink the activity (or drop it
  // entirely), never the persona/id/status/elapsed prefix.
  const activity = deriveActivity(run, Date.now());
  let left = baseLeft;
  if (activity !== undefined) {
    const sepText = " · ";
    const rightW = visibleWidth(right);
    const baseW = visibleWidth(baseLeft);
    const minSpace = right ? 1 : 0;
    const budget =
      width - baseW - rightW - minSpace - visibleWidth(sepText);
    // Only append if there's room for at least "· " + 2 chars of activity.
    if (budget >= 2) {
      const fitted =
        visibleWidth(activity) <= budget
          ? activity
          : truncateToWidth(activity, budget, "…", false);
      left = baseLeft + sepText + fitted;
    }
  }

  // Truncate to width if needed.
  const headerLine = padOrTruncate(left, right, width);
  // Slice 7 (D3): drop the trailing ruler so the header is two lines
  // (top ruler + status line) instead of three. The first turn body or
  // separator now flows directly under the status line, removing one
  // line of vertical chrome per render.
  return [sep, headerLine];
}

// ── Activity derivation (Slice 5b) ──────────────────────────────────

const IDLE_THRESHOLD_MS = 5000;

/**
 * Derive a one-segment activity descriptor for the live run. Returns
 * `undefined` when no activity should be shown (terminal/queued/paused
 * statuses, or no last message yet).
 *
 * Order of precedence:
 * 1. If status is not `running`, no activity.
 * 2. If `nowMs - lastEventAt >= IDLE_THRESHOLD_MS`, return `idle Ns` /
 *    `idle Nm`.
 * 3. Otherwise, scan the last assistant message's content from end to
 *    start; the first toolCall, thinking, or text part wins.
 */
export function deriveActivity(run: Run, nowMs: number): string | undefined {
  if (run.status !== "running") return undefined;

  const lastEvent = run.lastEventAt ?? run.startTime;
  const idleMs = nowMs - lastEvent;
  if (idleMs >= IDLE_THRESHOLD_MS) {
    const totalSecs = Math.floor(idleMs / 1000);
    if (totalSecs >= 60) {
      const mins = Math.floor(totalSecs / 60);
      return `idle ${mins}m`;
    }
    return `idle ${totalSecs}s`;
  }

  const last = run.messages.at(-1);
  if (!last) return undefined;
  const role = (last as any).role;
  if (role !== "assistant") return undefined;
  const content = (last as any).content;
  if (!Array.isArray(content)) return undefined;

  for (let i = content.length - 1; i >= 0; i--) {
    const part = content[i];
    const t = part?.type;
    if (t === "toolCall") {
      return formatToolCallShort(String(part.name ?? "tool"), part.arguments);
    }
    if (t === "thinking") return "thinking";
    if (t === "text") return "responding";
  }
  return undefined;
}

// ── Footer ────────────────────────────────────────────────────────────
//
// v0.8.3 Item 3 — Slice 9: footer rendering moved to
// `focused-stream-overlay.ts` (the only consumer of an interactive
// footer). The pure renderer no longer owns the hint list. The
// classifier (`transcript-classify.ts`) still recognises footer-shaped
// lines for legacy callers / fixtures, but no helper here produces
// them.

// ── Transcript body ───────────────────────────────────────────────────

export function renderTranscript(run: Run, opts: TranscriptOptions): string[] {
  const out: string[] = [];
  let assistantTurnIndex = 0;
  let msgIdx = -1;

  // Build a quick lookup: toolCall id → toolResult message (the toolResult
  // following an assistant message is the response to it).
  const resultsByCallId = new Map<string, AgentMessage>();
  for (const msg of run.messages) {
    if ((msg as any).role !== "toolResult") continue;
    const content = (msg as any).content;
    if (!Array.isArray(content)) continue;
    for (const part of content) {
      if (part?.type === "toolResult" && part.toolUseId) {
        resultsByCallId.set(part.toolUseId, msg);
      }
    }
  }

  for (const msg of run.messages) {
    msgIdx += 1;
    const role = (msg as any).role;
    if (role === "user" || role === "toolResult") {
      // toolResult is rendered inline with its toolCall, not as a top-level message.
      // user messages are the internal sub-agent prompt — hidden.
      continue;
    }

    if (role === "assistant") {
      assistantTurnIndex += 1;
      // Only emit a separator between consecutive assistant turns; the first
      // turn flows directly under the header. Single-turn transcripts get no
      // separator at all.
      if (assistantTurnIndex >= 2) {
        out.push(turnSeparator(assistantTurnIndex, opts.width));
      }

      const content = (msg as any).content;
      if (!Array.isArray(content)) continue;
      let partIdx = -1;
      for (const part of content) {
        partIdx += 1;
        switch (part?.type) {
          case "text":
            for (const line of wrap(String(part.text ?? ""), opts.width)) {
              out.push(line);
            }
            break;
          case "thinking":
            if (opts.showThinking) {
              const tkey = `thinking:${msgIdx}:${partIdx}`;
              const expanded = opts.isExpanded?.(tkey, false) ?? false;
              const block = renderThinking(String(part.thinking ?? ""), opts.width);
              const capped = expanded
                ? block
                : capBlock(block, THINKING_FOLD_LIMIT, opts.width);
              out.push(...capped);
            } else {
              out.push(renderThinkingSummary(String(part.thinking ?? "")));
            }
            break;
          case "toolCall": {
            const tkey = part.id
              ? `tool:${part.id}`
              : `tool:${msgIdx}:${partIdx}`;
            const expanded = opts.isExpanded?.(tkey, false) ?? false;
            const block = renderToolCall(part, resultsByCallId, opts);
            // Fold cap only applies in expanded mode — collapsed mode
            // is already a single chevron line + outcome (≤3 lines).
            const capped =
              opts.collapseToolCalls || expanded
                ? block
                : capBlock(block, TOOL_CALL_FOLD_LIMIT, opts.width);
            out.push(...capped);
            break;
          }
          default:
            // Unknown part types are skipped (forward-compat).
            break;
        }
      }
    }
  }

  return out;
}

// ── Helpers ───────────────────────────────────────────────────────────

function turnSeparator(turn: number, width: number): string {
  // Slice 4: single-line dim-friendly marker, no flanking rules. Slice 7
  // applies the dim color in the Component layer; this stays pure ASCII.
  const candidate = `· turn ${turn}`;
  if (visibleWidth(candidate) > width) return truncateToWidth(candidate, width, "…", false);
  return candidate;
}

function renderThinking(text: string, width: number): string[] {
  const out: string[] = ["  ┃ thinking"];
  for (const line of wrap(text, Math.max(8, width - 4))) {
    out.push("  ┃ " + line);
  }
  return out;
}

/**
 * Compact summary line emitted when `showThinking: false`. Lets the user see
 * that thinking happened (and roughly how much) without taking the vertical
 * cost of the body. Char count is the raw text length; line count is the
 * number of newline-separated segments, with empty text reporting 0 lines.
 *
 * Slice 7 will color the leading `·` via the component-layer styling helper.
 */
function renderThinkingSummary(text: string): string {
  const chars = text.length;
  const lines = text === "" ? 0 : text.split("\n").length;
  const lineWord = lines === 1 ? "line" : "lines";
  return `· thinking (${chars} chars / ${lines} ${lineWord})`;
}

function renderToolCall(
  part: { id?: string; name: string; arguments?: Record<string, any> },
  resultsByCallId: Map<string, AgentMessage>,
  opts: TranscriptOptions,
): string[] {
  const name = part.name ?? "tool";
  if (opts.collapseToolCalls) {
    const summary = summarizeToolArgs(name, part.arguments ?? {});
    const line = `▸ ${name}${summary ? " " + summary : ""}`;
    const out: string[] = [truncateOrPad(line, opts.width)];
    // Outcome line: ↳ ✓/✗/… + first-line preview. Only emitted when the
    // call carries an id we can correlate against; tests/fixtures that omit
    // id keep their pre-Slice-2 single-chevron shape.
    if (part.id) {
      const result = resultsByCallId.get(part.id);
      if (result) {
        const isError = (result as any).isError === true;
        const glyph = isError ? "✗" : "✓";
        const preview = firstLine(extractFirstResultText(result));
        const outcome = preview ? ` ↳ ${glyph} ${preview}` : ` ↳ ${glyph}`;
        out.push(truncateOrPad(outcome, opts.width));
      } else {
        // Pending: call landed but no result yet. Stable cue prevents the
        // ≤500ms flash described in plan §7 throttle interaction.
        out.push(truncateOrPad(" ↳ …", opts.width));
      }
    }
    return out;
  }

  const out: string[] = [`▾ ${name}`];
  // Pretty-print arguments line by line.
  if (part.arguments) {
    const json = JSON.stringify(part.arguments, null, 2);
    for (const ln of json.split("\n")) {
      out.push(truncateOrPad("  " + ln, opts.width));
    }
  }
  // Inline the matched tool result if present.
  if (part.id) {
    const result = resultsByCallId.get(part.id);
    if (result) {
      const content = (result as any).content;
      if (Array.isArray(content)) {
        for (const r of content) {
          const text = r?.text ?? r?.output ?? "";
          if (typeof text === "string" && text.trim()) {
            out.push(truncateOrPad("  ↳ " + firstLine(text), opts.width));
          }
        }
      }
    }
  }
  return out;
}

function extractFirstResultText(result: AgentMessage): string {
  const content = (result as any).content;
  if (!Array.isArray(content)) return "";
  for (const r of content) {
    const text = r?.text ?? r?.output ?? "";
    if (typeof text === "string" && text) return text;
  }
  return "";
}

function firstLine(s: string): string {
  const idx = s.indexOf("\n");
  return idx === -1 ? s : s.slice(0, idx);
}

// Width-aware wrapping/truncation.
//
// IMPORTANT: pi-tui's renderer measures lines with `visibleWidth`, which
// counts a tab (`\t`) as 3 columns and ignores ANSI escape sequences. If we
// wrap by raw `.length` / `.slice` (counting tabs as 1 char and ANSI as
// visible chars), the renderer crashes with
//   "Rendered line N exceeds terminal width (X > Y)"
// when a wrapped/padded line contains tabs or ANSI. Always go through
// pi-tui's helpers below.

function wrap(text: string, width: number): string[] {
  if (width <= 0) return [text];
  // wrapTextWithAnsi handles \n, ANSI escapes, tabs (=3 cols), and word
  // boundaries. Every returned line satisfies visibleWidth(line) <= width.
  return wrapTextWithAnsi(text, width);
}

function truncateOrPad(line: string, width: number): string {
  if (visibleWidth(line) <= width) return line;
  return truncateToWidth(line, width, "…", false);
}

function padOrTruncate(left: string, right: string, width: number): string {
  if (!right) {
    return visibleWidth(left) <= width
      ? left
      : truncateToWidth(left, width, "…", false);
  }
  const minSpace = 1;
  const leftW = visibleWidth(left);
  const rightW = visibleWidth(right);
  if (leftW + minSpace + rightW > width) {
    // Right-align right; truncate left if needed.
    const leftBudget = Math.max(0, width - rightW - minSpace);
    const leftCut =
      leftW > leftBudget ? truncateToWidth(left, leftBudget, "…", false) : left;
    const leftCutW = visibleWidth(leftCut);
    const pad = Math.max(minSpace, width - leftCutW - rightW);
    return leftCut + " ".repeat(pad) + right;
  }
  const pad = width - leftW - rightW;
  return left + " ".repeat(pad) + right;
}
