/**
 * pi-conductor — Config loader.
 *
 * Loads from ~/.pi/agent/extensions/conductor/config.json (user) and
 * <project>/.pi/conductor.json (project, overrides user).
 *
 * Two entry points:
 *   - loadConfig(cwd): ConductorConfig
 *       Silent-fallback for hot paths (every spawn re-reads config; we
 *       don't want chatty console.warn logs in the agent loop).
 *   - loadConfigWithErrors(cwd): { config, errors[] }
 *       Used by /conductor doctor to surface malformed config files to
 *       the user without crashing the session.
 *
 * Unknown fields are ignored (forward-compat). Bad-typed values silently
 * fall back to defaults — captured by the existing config tests.
 */

import { existsSync, readFileSync } from "node:fs";
import { homedir } from "node:os";
import { join } from "node:path";
import { DEFAULT_CONFIG, type ConductorConfig } from "./types.ts";

export function userConfigPath(): string {
  return join(homedir(), ".pi", "agent", "extensions", "conductor", "config.json");
}

export function projectConfigPath(cwd: string): string {
  return join(cwd, ".pi", "conductor.json");
}

export interface ConfigLoadError {
  path: string;
  reason: string;
}

export interface LoadConfigResult {
  config: ConductorConfig;
  /**
   * v0.11 slice 2: user-layer config, merged with defaults but NOT yet
   * combined with the project layer. Lets layer-aware callers (the
   * on_complete_hook cascade) introspect a single layer in isolation.
   *
   * For backward-compat callers that only want the merged result,
   * `config` continues to be the merged user+project blob (and
   * `loadConfig()` returns that directly).
   */
  user: ConductorConfig;
  /**
   * v0.11 slice 2: project-layer config, merged with defaults but NOT
   * yet combined with the user layer. See {@link user} for rationale.
   */
  project: ConductorConfig;
  errors: ConfigLoadError[];
}

interface ReadResult {
  value: unknown;
  error?: ConfigLoadError;
}

function safeReadJson(path: string): ReadResult {
  if (!existsSync(path)) return { value: null };
  try {
    return { value: JSON.parse(readFileSync(path, "utf-8")) };
  } catch (e) {
    return {
      value: null,
      error: { path, reason: (e as Error).message },
    };
  }
}

function mergeConfig(base: ConductorConfig, raw: unknown): ConductorConfig {
  if (!raw || typeof raw !== "object") return base;
  const r = raw as Record<string, unknown>;
  const out: ConductorConfig = { ...base };

  if (typeof r.defaultTimeoutMinutes === "number" && r.defaultTimeoutMinutes > 0) {
    out.defaultTimeoutMinutes = r.defaultTimeoutMinutes;
  }
  if (typeof r.maxConcurrent === "number" && r.maxConcurrent >= 1) {
    out.maxConcurrent = Math.floor(r.maxConcurrent);
  }
  if (
    typeof r.maxConcurrentWriteCapable === "number" &&
    r.maxConcurrentWriteCapable >= 1
  ) {
    out.maxConcurrentWriteCapable = Math.floor(r.maxConcurrentWriteCapable);
  }
  if (typeof r.queueOnConcurrencyCap === "boolean") {
    out.queueOnConcurrencyCap = r.queueOnConcurrencyCap;
  }
  if (typeof r.autoOpenFocusOnSpawn === "boolean") {
    out.autoOpenFocusOnSpawn = r.autoOpenFocusOnSpawn;
  }
  if (r.defaultSpawnMode === "foreground" || r.defaultSpawnMode === "background") {
    out.defaultSpawnMode = r.defaultSpawnMode;
  }
  if (r.defaultMode === "on" || r.defaultMode === "off") {
    out.defaultMode = r.defaultMode;
  }
  if (r.personaOverrides && typeof r.personaOverrides === "object") {
    // Field-level merge per persona name. A project entry that touches
    // `thinking` does not blow away a user entry's `model`.
    const incoming = r.personaOverrides as Record<string, Record<string, unknown>>;
    const merged = { ...out.personaOverrides } as Record<string, Record<string, unknown>>;
    for (const [name, fields] of Object.entries(incoming)) {
      if (!fields || typeof fields !== "object") continue;
      merged[name] = { ...(merged[name] ?? {}), ...fields };
    }
    out.personaOverrides = merged as unknown as ConductorConfig["personaOverrides"];
  }
  if (typeof r.conductorPromptPath === "string") {
    out.conductorPromptPath = r.conductorPromptPath;
  }

  if (r.gc && typeof r.gc === "object") {
    out.gc = mergeGcConfig(out.gc, r.gc as Record<string, unknown>);
  }

  return out;
}

function mergeGcConfig(
  base: ConductorConfig["gc"],
  raw: Record<string, unknown>,
): ConductorConfig["gc"] {
  const out = { ...base };
  if (typeof raw.enabled === "boolean") out.enabled = raw.enabled;
  if (typeof raw.completedTtlDays === "number" && raw.completedTtlDays > 0) {
    out.completedTtlDays = Math.floor(raw.completedTtlDays);
  }
  if (typeof raw.failedTtlDays === "number" && raw.failedTtlDays > 0) {
    out.failedTtlDays = Math.floor(raw.failedTtlDays);
  }
  if (typeof raw.totalSizeBudgetBytes === "number" && raw.totalSizeBudgetBytes >= 0) {
    out.totalSizeBudgetBytes = Math.floor(raw.totalSizeBudgetBytes);
  }
  if (typeof raw.transcriptSizeCapBytes === "number" && raw.transcriptSizeCapBytes >= 0) {
    out.transcriptSizeCapBytes = Math.floor(raw.transcriptSizeCapBytes);
  }
  if (typeof raw.orphanReconcileAfterHours === "number" && raw.orphanReconcileAfterHours > 0) {
    out.orphanReconcileAfterHours = raw.orphanReconcileAfterHours;
  }
  if (typeof raw.autoOnSessionStart === "boolean") {
    out.autoOnSessionStart = raw.autoOnSessionStart;
  }
  if (typeof raw.autoDebounceHours === "number" && raw.autoDebounceHours >= 0) {
    out.autoDebounceHours = raw.autoDebounceHours;
  }
  if (raw.perPersonaTtlDays && typeof raw.perPersonaTtlDays === "object") {
    const incoming = raw.perPersonaTtlDays as Record<string, unknown>;
    const merged = { ...out.perPersonaTtlDays };
    for (const [name, days] of Object.entries(incoming)) {
      if (typeof days === "number" && days > 0) {
        merged[name] = Math.floor(days);
      }
    }
    out.perPersonaTtlDays = merged;
  }
  return out;
}

/**
 * Load config and return both the resolved config and any file-load errors.
 * Use this when surfacing config health to the user (e.g. /conductor doctor).
 *
 * v0.11 slice 2: also returns user- and project-layer configs separately
 * (each merged with defaults but not combined with the other layer). The
 * on_complete_hook cascade resolver needs to see the layers independently
 * so a project override can shadow a user override predictably; the
 * default merge collapses them into a field-level union (see
 * {@link mergeConfig}). Callers that only need the merged result use
 * `result.config` exactly as before.
 */
export function loadConfigWithErrors(cwd: string): LoadConfigResult {
  const errors: ConfigLoadError[] = [];

  const u = safeReadJson(userConfigPath());
  if (u.error) errors.push(u.error);
  const userCfg = mergeConfig({ ...DEFAULT_CONFIG }, u.value);

  const p = safeReadJson(projectConfigPath(cwd));
  if (p.error) errors.push(p.error);
  const projectCfg = mergeConfig({ ...DEFAULT_CONFIG }, p.value);

  // Combined view: defaults <- user <- project.
  let merged = mergeConfig({ ...DEFAULT_CONFIG }, u.value);
  merged = mergeConfig(merged, p.value);

  return { config: merged, user: userCfg, project: projectCfg, errors };
}

/**
 * Silent-fallback wrapper around loadConfigWithErrors. Use this in hot
 * paths (every ensemble_spawn invocation re-reads config). Errors are
 * discarded — surfacing them is /conductor doctor's job.
 */
export function loadConfig(cwd: string): ConductorConfig {
  return loadConfigWithErrors(cwd).config;
}
